const item = $input.item;
// Use optional chaining to prevent errors if html is missing
const html = item.json.html || item.json.text || "";
const banks = ["cimb", "maybank", "alliance", "sc", "hsbc", "rhb"];
const regex = new RegExp(`\\b(${banks.join("|")})\\b`, "i");
const match = html.match(regex);

let bankName = null;
if (match) {
  bankName = match[1].toLowerCase();
}

// Set the value back to the JSON
item.json.bankName = bankName;

// Handle Binary Attachments
if (item.binary) {
  let firstPdf = null;

  for (const key of Object.keys(item.binary)) {
    const attachment = item.binary[key];
    if (attachment.mimeType === 'application/pdf') {
      firstPdf = attachment;
      break;
    }
  }

  if (firstPdf) {
    // Overwrite binary to only include the first PDF
    item.binary = { data: firstPdf }; 
  }
}

return item;

// Replace "country" with whatever field you want to check
const inputFieldName = "bankName";
const outputFieldName = "password";

// Now write our result depending on the input field value
switch ($input.item.json[inputFieldName]) {
  case 'maybank':
    $input.item.json[outputFieldName] = '***REMOVED***';
    break;
  case 'cimb':
    $input.item.json[outputFieldName] = '***REMOVED***';
    break;
  case 'sc':
    $input.item.json[outputFieldName] = '***REMOVED***';
    break;
  case 'alliance':
    $input.item.json[outputFieldName] = '***REMOVED***';
    break
  case 'hsbc':
    $input.item.json[outputFieldName] = '***REMOVED***';
    break;
  case 'rhb':
    $input.item.json[outputFieldName] = '***REMOVED***';
    break;    
  default:
    $input.item.json.error = 'Could not validate bankName';
}

return $input.item;

